'use client';

import { useAuth } from '@/components/auth/auth-context';
import { useRouter } from 'next/navigation';
import { useEffect, useState, useRef } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  FileText,
  Calendar,
  Users,
  Video,
  LogOut,
  Menu,
  X,
  Settings,
  Shield,
  ShieldAlert,
  Hash,
  History,
  Radio,
  Mail,
  Home,
  Megaphone,
  ChevronUp,
  User as UserIcon,
  HardDrive
} from 'lucide-react';

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const { user, logout, isLoading } = useAuth();
  const router = useRouter();
  const pathname = usePathname();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMounted, setIsMounted] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  console.log('[AdminLayout] Render', { isLoading, user: !!user, pathname });

  // Ensure component is mounted before rendering auth-dependent content
  useEffect(() => {
    console.log('[AdminLayout] Mounted');
    setIsMounted(true);
    return () => console.log('[AdminLayout] Unmounted');
  }, []);

  // Auth Guard
  useEffect(() => {
    if (pathname === '/admin/login') return;

    if (!isLoading) {
      if (!user) {
        router.push('/admin/login');
      } else if (!['superadmin', 'admin', 'editor', 'redaksi'].includes(user.role as string)) {
        router.push('/');
      }
    }
  }, [user, isLoading, router, pathname]);

  // Close dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Close dropdown on navigation
  useEffect(() => {
    setIsProfileOpen(false);
  }, [pathname]);

  if (pathname === '/admin/login') {
    return <>{children}</>;
  }

  if (!isMounted) {
    return null;
  }

  if (isLoading) return <div className="min-h-screen flex items-center justify-center bg-gray-100">Loading...</div>;
  if (!user) return null;

  const menuItems = [
    { label: 'Dashboard', href: '/admin', icon: Home, roles: ['superadmin', 'admin', 'editor', 'redaksi'] },
    { label: 'Berita / Posts', href: '/admin/posts', icon: FileText, roles: ['superadmin', 'admin', 'editor', 'redaksi'] },
    { label: 'Kategori', href: '/admin/categories', icon: Hash, roles: ['superadmin', 'admin', 'editor'] },
    { label: 'Live Stream', href: '/admin/live-streams', icon: Radio, roles: ['superadmin', 'admin', 'editor'] },
    { label: 'Agenda', href: '/admin/agenda', icon: Calendar, roles: ['superadmin', 'admin', 'editor'] },
    { label: 'Banom', href: '/admin/banom', icon: Shield, roles: ['superadmin', 'admin'] },
    { label: 'Sejarah', href: '/admin/histories', icon: History, roles: ['superadmin', 'admin'] },
    { label: 'Multimedia', href: '/admin/multimedia', icon: Video, roles: ['superadmin', 'admin', 'editor'] },
    { label: 'Iklan', href: '/admin/ads', icon: Megaphone, roles: ['superadmin', 'admin', 'editor', 'redaksi'] },
    { label: 'Newsletter', href: '/admin/newsletters', icon: Mail, roles: ['superadmin', 'admin'] },
    { label: 'Users', href: '/admin/users', icon: Users, roles: ['superadmin'] },
    { label: 'Roles & Permissions', href: '/admin/roles', icon: ShieldAlert, roles: ['superadmin'] },
    { label: 'Backup & Restore', href: '/admin/backup', icon: HardDrive, roles: ['superadmin'] },
    { label: 'Settings', href: '/admin/settings', icon: Settings, roles: ['superadmin'] },
  ];

  const filteredMenu = menuItems.filter(item => item.roles.includes(user.role as string));

  return (
    <div className="min-h-screen bg-gray-100 flex">
      {/* Sidebar */}
      <aside
        className={`fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-200 transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'
          } lg:translate-x-0`}
      >
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-gray-200 flex items-center justify-between">
            <Link href="/" className="font-serif font-bold text-xl text-green-800">
              NU | ADMIN
            </Link>
            <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden">
              <X className="w-5 h-5" />
            </button>
          </div>

          <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            <div className="px-2 mb-4">
              <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Menu</p>
            </div>
            {filteredMenu.map((item) => {
              const isActive = pathname === item.href || (item.href !== '/admin' && pathname.startsWith(item.href));
              return (
                <Link
                  key={item.href}
                  href={item.href}
                  onClick={() => setIsSidebarOpen(false)}
                  className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${isActive
                    ? 'bg-green-50 text-green-700'
                    : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                    }`}
                >
                  <item.icon className="w-5 h-5" />
                  {item.label}
                </Link>
              );
            })}
          </nav>

          {/* User Profile Section with Dropdown */}
          <div className="relative border-t border-gray-200" ref={profileRef}>
            {/* Dropdown Menu */}
            {isProfileOpen && (
              <div className="absolute bottom-full left-0 right-0 mx-3 mb-1 bg-white border border-gray-200 rounded-xl shadow-lg overflow-hidden z-50">
                <Link
                  href="/admin/profile"
                  onClick={() => { setIsProfileOpen(false); setIsSidebarOpen(false); }}
                  className={`flex items-center gap-3 px-4 py-3 text-sm font-medium transition-colors ${pathname === '/admin/profile'
                    ? 'bg-green-50 text-green-700'
                    : 'text-gray-700 hover:bg-gray-50'
                    }`}
                >
                  <UserIcon className="w-4 h-4" />
                  Profil Saya
                </Link>
                <div className="border-t border-gray-100" />
                <button
                  onClick={() => { setIsProfileOpen(false); logout(); }}
                  className="w-full flex items-center gap-3 px-4 py-3 text-sm font-medium text-red-600 hover:bg-red-50 transition-colors"
                >
                  <LogOut className="w-4 h-4" />
                  Keluar
                </button>
              </div>
            )}

            {/* User Info Button */}
            <button
              onClick={() => setIsProfileOpen(!isProfileOpen)}
              className="w-full flex items-center gap-3 px-4 py-4 hover:bg-gray-50 transition-colors text-left"
            >
              <div className="w-9 h-9 rounded-full bg-green-100 flex items-center justify-center text-green-700 font-bold flex-shrink-0 overflow-hidden">
                {user.avatar ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                ) : (
                  user.name.charAt(0).toUpperCase()
                )}
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-sm font-medium text-gray-900 truncate">{user.name}</p>
                <p className="text-xs text-gray-500 truncate capitalize">{user.role}</p>
              </div>
              <ChevronUp className={`w-4 h-4 text-gray-400 transition-transform duration-200 ${isProfileOpen ? '' : 'rotate-180'}`} />
            </button>
          </div>
        </div>
      </aside>

      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div
          className="fixed inset-0 bg-black/30 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden lg:ml-64">
        {/* Mobile Header */}
        <header className="lg:hidden bg-white border-b border-gray-200 p-4 flex items-center justify-between">
          <button onClick={() => setIsSidebarOpen(true)}>
            <Menu className="w-6 h-6" />
          </button>
          <span className="font-bold">Admin Panel</span>
          <div className="w-6" /> {/* Spacer */}
        </header>

        <main className="flex-1 overflow-y-auto p-4 lg:p-8">
          {children}
        </main>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { api } from '@/components/auth/auth-context';
import { createLiveStreamService } from '@/lib/services/live-stream.service';
import { useRouter } from 'next/navigation';
import { ChevronLeft, Save, Loader2, Video, AlertCircle, RefreshCw, Youtube, CheckCircle } from 'lucide-react';
import Link from 'next/link';

const getErrorMessage = (error: unknown): string => {
  const apiMessage = (error as { response?: { data?: { message?: string } } }).response?.data?.message;
  if (typeof apiMessage === 'string' && apiMessage.trim()) return apiMessage;
  return error instanceof Error ? error.message : 'Unknown error';
};

const liveStreamService = createLiveStreamService(api);

export default function CreateLiveStreamPage() {
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    youtube_id: '',
    is_active: true,
    scheduled_start_time: '',
    title: '',
    channel_name: ''
  });

  const [channelId, setChannelId] = useState('');
  const [isFetching, setIsFetching] = useState(false);

  const [isYoutubeConnected, setIsYoutubeConnected] = useState(false);
  const [myBroadcasts, setMyBroadcasts] = useState<any[]>([]);
  const [isFetchingBroadcasts, setIsFetchingBroadcasts] = useState(false);

  // Check YouTube connection status
  useEffect(() => {
    liveStreamService.checkYoutubeStatus().then(res => {
      setIsYoutubeConnected(res.connected);
    }).catch(console.error);
  }, []);

  const handleFetchFromChannel = async () => {
    if (!channelId.trim()) {
      setError('Masukkan Channel ID terlebih dahulu');
      return;
    }

    setIsFetching(true);
    setError(null);
    setSuccessMsg(null);

    try {
      const data = await liveStreamService.fetchFromChannel(channelId.trim());
      setFormData({
        ...formData,
        youtube_id: data.youtube_id,
        title: data.title || '',
        channel_name: data.channel_name || '',
      });
      if ((data as any).message) {
        setSuccessMsg((data as any).message);
      } else {
        setSuccessMsg('Siaran aktif berhasil dimuat dari channel.');
      }
    } catch (err) {
      setError(getErrorMessage(err));
    } finally {
      setIsFetching(false);
    }
  };

  const handleFetchMyBroadcasts = async () => {
    setIsFetchingBroadcasts(true);
    setError(null);
    try {
      const broadcasts = await liveStreamService.getMyBroadcasts();
      setMyBroadcasts(broadcasts);
      if (broadcasts.length === 0) {
        setError('Tidak ada siaran ditemukan di akun YouTube Anda.');
      }
    } catch (err) {
      setError(getErrorMessage(err));
    } finally {
      setIsFetchingBroadcasts(false);
    }
  };

  const handleSelectBroadcast = (broadcast: any) => {
    setFormData({
      ...formData,
      youtube_id: broadcast.id,
      title: broadcast.title || '',
      scheduled_start_time: broadcast.scheduledStartTime ? broadcast.scheduledStartTime.slice(0, 16) : '',
    });
    // Scroll to form or give feedback
    window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.youtube_id.trim()) {
      setError('YouTube Video ID harus diisi');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const payload = {
        youtube_id: formData.youtube_id.trim(),
        is_active: formData.is_active,
        scheduled_start_time: formData.scheduled_start_time || undefined,
        title: formData.title || undefined,
        channel_name: formData.channel_name || undefined,
      };

      await liveStreamService.create(payload);
      router.push('/admin/live-streams');
    } catch (err) {
      const message = getErrorMessage(err);
      console.error('Failed to create live stream:', message);
      setError(message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto">
      <div className="flex items-center gap-4 mb-8">
        <Link href="/admin/live-streams" className="p-2 hover:bg-gray-100 rounded-lg transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-600" />
        </Link>
        <h1 className="text-2xl font-bold text-gray-900">Tambah Siaran Langsung</h1>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 sm:p-8">
        {/* Error Alert */}
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
            <div>
              <h3 className="font-semibold text-red-900">Terjadi Kesalahan</h3>
              <p className="text-sm text-red-700">{error}</p>
            </div>
          </div>
        )}

        {/* Success Alert */}
        {successMsg && (
          <div className="mb-6 p-4 bg-emerald-50 border border-emerald-200 rounded-lg flex items-start gap-3">
            <CheckCircle className="w-5 h-5 text-emerald-600 flex-shrink-0 mt-0.5" />
            <div>
              <h3 className="font-semibold text-emerald-900">Berhasil</h3>
              <p className="text-sm text-emerald-700">{successMsg}</p>
            </div>
          </div>
        )}

        <div className="space-y-6">
          <div className="bg-blue-50 text-blue-800 p-4 rounded-lg text-sm mb-6 flex gap-3">
            <Video className="w-5 h-5 flex-shrink-0 mt-0.5" />
            <div>
              <p className="font-bold mb-1">Otomasi YouTube</p>
              <p>Gunakan Fitur ini untuk mengambil siaran yang sedang "LIVE" secara otomatis dari Channel tertentu.</p>
            </div>
          </div>

          {isYoutubeConnected && (
            <div className="p-4 border border-red-100 bg-red-50/30 rounded-lg mb-8">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 flex items-center gap-2">
                    <Youtube className="w-4 h-4 text-red-600" />
                    Ambil dari Akun YouTube Anda
                  </label>
                  <p className="text-[10px] text-gray-500 mt-1">Pilih siaran yang sudah dijadwalkan atau sedang live dari akun yang terhubung.</p>
                </div>
                <button
                  type="button"
                  onClick={handleFetchMyBroadcasts}
                  disabled={isFetchingBroadcasts}
                  className="px-3 py-1.5 bg-red-600 text-white rounded font-medium hover:bg-red-700 transition-colors disabled:opacity-50 flex items-center gap-2 text-xs w-full sm:w-auto justify-center"
                >
                  {isFetchingBroadcasts ? <Loader2 className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                  Muat Siaran Saya
                </button>
              </div>

              {myBroadcasts.length > 0 && (
                <div className="space-y-2 mt-4 max-h-60 overflow-y-auto pr-2">
                  {myBroadcasts.map(b => (
                    <div
                      key={b.id}
                      onClick={() => handleSelectBroadcast(b)}
                      className={`flex items-start gap-3 p-3 rounded-lg border cursor-pointer transition-all ${formData.youtube_id === b.id
                        ? 'bg-red-50 border-red-300 shadow-sm ring-1 ring-red-200'
                        : 'bg-white border-gray-200 hover:border-red-200 hover:bg-gray-50'
                        }`}
                    >
                      {b.thumbnail_url && (
                        <div className="w-24 h-16 bg-black rounded overflow-hidden flex-shrink-0 relative">
                          {/* eslint-disable-next-line @next/next/no-img-element */}
                          <img src={b.thumbnail_url} alt="" className="w-full h-full object-cover" />
                          {b.status === 'live' && (
                            <span className="absolute bottom-1 right-1 bg-red-600 text-white text-[10px] px-1 rounded font-bold">
                              LIVE
                            </span>
                          )}
                        </div>
                      )}
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-gray-900 line-clamp-1">{b.title}</p>
                        <p className="text-xs text-gray-500 mt-1">Status: <span className="font-medium uppercase">{b.status}</span></p>
                        {b.scheduledStartTime && <p className="text-[10px] text-gray-400">Jadwal: {new Date(b.scheduledStartTime).toLocaleString('id-ID')}</p>}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          <div className="p-4 border border-blue-100 bg-blue-50/30 rounded-lg mb-8">
            <label className="block text-sm font-medium text-gray-700 mb-2">Ambil Otomatis dari Channel ID</label>
            <div className="flex gap-2">
              <input
                type="text"
                value={channelId}
                onChange={(e) => setChannelId(e.target.value)}
                className="flex-1 px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono text-sm"
                placeholder="Contoh: UCj... (Channel ID)"
              />
              <button
                type="button"
                onClick={handleFetchFromChannel}
                disabled={isFetching}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center gap-2 text-sm"
              >
                {isFetching ? <Loader2 className="w-4 h-4 animate-spin" /> : <Video className="w-4 h-4" />}
                Ambil Siaran Aktif
              </button>
            </div>
            <p className="text-[10px] text-gray-500 mt-1">Sistem akan mencari video yang berstatus "LIVE" di Channel tersebut.</p>
          </div>

          <div className="relative">
            <div className="absolute inset-0 flex items-center" aria-hidden="true">
              <div className="w-full border-t border-gray-200"></div>
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="bg-white px-2 text-gray-400 font-medium">ATAU MASUKKAN MANUAL</span>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">YouTube Video ID *</label>
              <input
                type="text"
                required
                value={formData.youtube_id}
                onChange={(e) => setFormData({ ...formData, youtube_id: e.target.value })}
                onFocus={() => setError(null)}
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500 font-mono"
                placeholder="Contoh: Kz3FK5FbBz8"
              />
              <p className="text-xs text-gray-500 mt-1">ID unik video dari URL YouTube (v=...)</p>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Judul Siaran (Opsional - akan diambil dari YouTube)</label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
                placeholder="Biarkan kosong untuk ambil dari YouTube"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Nama Channel (Opsional - akan diambil dari YouTube)</label>
              <input
                type="text"
                value={formData.channel_name}
                onChange={(e) => setFormData({ ...formData, channel_name: e.target.value })}
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
                placeholder="Biarkan kosong untuk ambil dari YouTube"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Jadwal Tayang (Opsional)</label>
              <input
                type="datetime-local"
                value={formData.scheduled_start_time}
                onChange={(e) => setFormData({ ...formData, scheduled_start_time: e.target.value })}
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              />
              <p className="text-xs text-gray-500 mt-1">Kosongkan jika siaran sudah berlangsung</p>
            </div>

            <div className="pt-4 border-t border-gray-100">
              <label className="flex items-center gap-3 cursor-pointer p-3 rounded-lg border border-gray-200 hover:bg-gray-50 transition-colors">
                <input
                  type="checkbox"
                  checked={formData.is_active}
                  onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
                  className="w-5 h-5 text-green-600 rounded focus:ring-green-500"
                />
                <div>
                  <span className="font-medium text-gray-900 block">Set sebagai Siaran Aktif (LIVE)</span>
                  <span className="text-xs text-gray-500">Akan menonaktifkan siaran lain yang sedang aktif.</span>
                </div>
              </label>
            </div>

            <div className="pt-6 border-t border-gray-100 flex justify-end gap-3">
              <Link
                href="/admin/live-streams"
                className="px-4 py-2 border border-gray-200 rounded-lg font-medium text-gray-700 hover:bg-gray-50 transition-colors"
              >
                Batal
              </Link>
              <button
                type="submit"
                disabled={isLoading}
                className="flex items-center gap-2 px-6 py-2 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isLoading ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Menyimpan...
                  </>
                ) : (
                  <>
                    <Save className="w-4 h-4" />
                    Simpan Siaran
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { api } from '@/components/auth/auth-context';
import { createLiveStreamService, LiveStream } from '@/lib/services/live-stream.service';
import {
  Plus,
  Search,
  Edit,
  Trash2,
  Video,
  Radio,
  AlertCircle,
  RefreshCw,
  Youtube,
  LogOut
} from 'lucide-react';
import Link from 'next/link';
import { useSearchParams, useRouter } from 'next/navigation';

const getErrorMessage = (error: unknown): string => {
  const apiMessage = (error as { response?: { data?: { message?: string } } }).response?.data?.message;
  if (typeof apiMessage === 'string' && apiMessage.trim()) return apiMessage;
  return error instanceof Error ? error.message : 'Unknown error occurred';
};

const liveStreamService = createLiveStreamService(api);

export default function LiveStreamsPage() {
  const [streams, setStreams] = useState<LiveStream[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<number | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [isRefreshing, setIsRefreshing] = useState<number | null>(null);
  const [isYoutubeConnected, setIsYoutubeConnected] = useState(false);
  const [youtubeAuthLoading, setYoutubeAuthLoading] = useState(true);

  const searchParams = useSearchParams();
  const router = useRouter();

  console.log('[LiveStreamsPage] Render', { isLoading, streams: streams.length });

  useEffect(() => {
    console.log('[LiveStreamsPage] Mounted');
    return () => console.log('[LiveStreamsPage] Unmounted');
  }, []);

  const fetchStreams = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);
      const result = await liveStreamService.getAll();
      setStreams(result.streams);
    } catch (err) {
      const message = getErrorMessage(err);
      console.error('Failed to fetch live streams:', message);
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const checkYoutubeStatus = useCallback(async () => {
    try {
      setYoutubeAuthLoading(true);
      const res = await liveStreamService.checkYoutubeStatus();
      setIsYoutubeConnected(res.connected);
    } catch (err) {
      console.error('Failed to check YouTube status:', err);
    } finally {
      setYoutubeAuthLoading(false);
    }
  }, []);

  useEffect(() => {
    console.log('[LiveStreamsPage] fetchStreams Effect running');
    fetchStreams();
    checkYoutubeStatus();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const authStatus = searchParams.get('youtube_auth');
    if (authStatus === 'success') {
      setSuccessMessage('Berhasil terhubung dengan YouTube!');
      router.replace('/admin/live-streams');
    } else if (authStatus === 'error') {
      setError('Gagal menghubungkan dengan YouTube.');
      router.replace('/admin/live-streams');
    }
  }, [searchParams, router]);

  const handleDelete = async (id: number) => {
    if (!confirm('Apakah Anda yakin ingin menghapus siaran ini?')) {
      return;
    }

    try {
      setIsDeleting(id);
      setError(null);
      await liveStreamService.delete(id);
      setSuccessMessage('Siaran berhasil dihapus');
      setTimeout(() => setSuccessMessage(null), 3000);
      await fetchStreams();
    } catch (err) {
      const message = getErrorMessage(err);
      console.error('Failed to delete live stream:', message);
      setError(message);
    } finally {
      setIsDeleting(null);
    }
  };

  const handleRefresh = async (id: number) => {
    try {
      setIsRefreshing(id);
      setError(null);
      await liveStreamService.refresh(id);
      setSuccessMessage('Data siaran berhasil diperbarui dari YouTube');
      setTimeout(() => setSuccessMessage(null), 3000);
      await fetchStreams();
    } catch (err) {
      const message = getErrorMessage(err);
      console.error('Failed to refresh live stream:', message);
      setError(message);
    } finally {
      setIsRefreshing(null);
    }
  };

  const filteredStreams = (streams || []).filter(stream => {
    if (!stream) return false;
    const title = (stream?.title ?? '').toString().toLowerCase();
    const channelName = (stream?.channel_name ?? '').toString().toLowerCase();
    const query = (searchQuery ?? '').toString().toLowerCase();
    return title.includes(query) || channelName.includes(query);
  });

  return (
    <div>
      {/* Error Alert */}
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
          <AlertCircle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-red-900">Terjadi Kesalahan</h3>
            <p className="text-sm text-red-700">{error}</p>
          </div>
        </div>
      )}

      {/* Success Alert */}
      {successMessage && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-lg flex items-start gap-3">
          <div className="w-5 h-5 rounded-full bg-green-500 flex-shrink-0 mt-0.5" />
          <p className="text-sm text-green-700 font-medium">{successMessage}</p>
        </div>
      )}

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Management Siaran Langsung</h1>
          <p className="text-gray-500 text-sm mt-1">Kelola jadwal dan siaran langsung YouTube.</p>
        </div>

        <div className="flex gap-2">
          {youtubeAuthLoading ? (
            <div className="px-4 py-2 border border-gray-200 rounded-lg flex items-center justify-center">
              <div className="w-5 h-5 rounded-full border-2 border-gray-200 border-t-red-600 animate-spin" />
            </div>
          ) : isYoutubeConnected ? (
            <button
              onClick={async () => {
                if (confirm('Putuskan koneksi YouTube?')) {
                  await liveStreamService.disconnectYoutube();
                  checkYoutubeStatus();
                }
              }}
              className="bg-red-50 text-red-600 border border-red-200 px-4 py-2 rounded-lg font-medium hover:bg-red-100 transition-colors flex items-center gap-2"
              title="Putuskan Koneksi YouTube"
            >
              <Youtube className="w-4 h-4" />
              <span className="hidden sm:inline">Terhubung</span>
            </button>
          ) : (
            <button
              onClick={async () => {
                try {
                  const url = await liveStreamService.getYoutubeAuthUrl();
                  if (url) window.location.href = url;
                } catch (err) {
                  setError('Gagal mendapatkan URL otentikasi YouTube.');
                }
              }}
              className="bg-red-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-red-700 transition-colors flex items-center gap-2"
            >
              <Youtube className="w-4 h-4" />
              <span className="hidden sm:inline">Hubungkan YouTube</span>
            </button>
          )}

          <Link
            href="/admin/live-streams/create"
            className="bg-green-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-700 transition-colors flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            <span className="hidden sm:inline">Tambah Siaran</span>
            <span className="sm:hidden">Tambah</span>
          </Link>
        </div>
      </div>

      {/* Filters & Search */}
      <div className="bg-white p-4 rounded-xl border border-gray-200 mb-6 flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Cari siaran..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
          />
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold tracking-wider">
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Judul & Channel</th>
