const DEFAULT_REVALIDATE_SECONDS = 86400; // 24 hours
const getBackendApiBaseUrl = () => `${getBackendBaseUrl()}/api`;

// Static routes
const STATIC_ROUTES: MetadataRoute.Sitemap = [
