'use client';

import { createContext, useContext, useState, useEffect, useMemo, ReactNode } from 'react';
import axios from 'axios';
import { SetPasswordModal } from './set-password-modal';

interface User {
  id: number;
  name: string;
  email: string;
  avatar?: string | null;
  role: string;
  auth_provider?: string;
  last_login_at?: string | null;
  last_login_ip?: string | null;
  needs_password?: boolean;
}

type AuthPortal = 'public' | 'admin';

interface RegisterPayload {
  name: string;
  email: string;
  password: string;
  avatar?: string;
  portal?: AuthPortal;
}

interface AuthContextType {
  user: User | null;
  login: (email: string, password: string, portal?: AuthPortal) => Promise<void>;
  register: (payload: RegisterPayload) => Promise<void>;
  loginWithGoogle: (idToken: string, portal?: AuthPortal) => Promise<void>;
  logout: () => Promise<void>;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);
const AUTH_TOKEN_KEY = 'auth_token';
const USER_SESSION_KEY = 'user_session';
const DEVICE_FINGERPRINT_KEY = 'device_fingerprint';

// Get API base URL from environment variable
// In production: NEXT_PUBLIC_API_URL should be set to https://api.nulumbung.or.id/api
// In development: falls back to http://localhost:8000/api
const getApiBaseUrl = () => {
  // Priority: Use full backend URL for direct API access (bypasses Next.js proxy limits)
  const backendUrl = process.env.NEXT_PUBLIC_BACKEND_URL;

  // If we are on the SERVER SIDE (Node.js SSR), we MUST use the absolute URL.
  // Relative URLs like '/api' will cause Axios Network Error because it lacks a host.
  if (typeof window === 'undefined') {
    return backendUrl ? `${backendUrl.replace(/\/$/, '')}/api` : 'http://127.0.0.1:8000/api';
  }

  // If we are on the CLIENT SIDE, we should also prefer absolute to avoid proxy issues,
  // but fallback to relative '/api' if NEXT_PUBLIC_BACKEND_URL is somehow missing.
  if (backendUrl) {
    return `${backendUrl.replace(/\/$/, '')}/api`;
  }

  return '/api';
};

// Axios instance with base URL
const api = axios.create({
  baseURL: getApiBaseUrl(),
  headers: {
    'Accept': 'application/json',
  },
});

api.interceptors.request.use((config) => {
  if (typeof window !== 'undefined') {
    const token = localStorage.getItem(AUTH_TOKEN_KEY);
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
  }
  return config;
}, (error) => Promise.reject(error));

const parseStoredUser = (): User | null => {
  if (typeof window === 'undefined') {
    return null;
  }

  const raw = localStorage.getItem(USER_SESSION_KEY);
  if (!raw) return null;

  try {
    return JSON.parse(raw) as User;
  } catch {
    localStorage.removeItem(USER_SESSION_KEY);
    return null;
  }
};

const getStoredToken = (): string | null => {
  if (typeof window === 'undefined') {
    return null;
  }
  return localStorage.getItem(AUTH_TOKEN_KEY);
};

const setAuthHeader = (token?: string) => {
  // Now handled primarily by the Axios interceptor
  // But we can keep this for explicit state changes if needed
  if (!token) {
    delete api.defaults.headers.common['Authorization'];
    return;
  }
  api.defaults.headers.common['Authorization'] = `Bearer ${token}`;
};

const ensureDeviceFingerprint = () => {
  if (typeof window === 'undefined') {
    return 'server-render';
  }

  const existing = localStorage.getItem(DEVICE_FINGERPRINT_KEY);
  if (existing) {
    return existing;
  }

  const generated = typeof crypto !== 'undefined' && 'randomUUID' in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;

  localStorage.setItem(DEVICE_FINGERPRINT_KEY, generated);
  return generated;
};

const getDevicePayload = () => {
  if (typeof window === 'undefined') {
    return {};
  }

  const metadata = {
    platform: navigator.platform,
    language: navigator.language,
    timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
    userAgent: navigator.userAgent,
  };

  return {
    device_fingerprint: ensureDeviceFingerprint(),
    device_name: navigator.platform || 'Unknown Device',
    device_metadata: metadata,
  };
};

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  const persistSession = (nextUser: User, token: string) => {
    localStorage.setItem(AUTH_TOKEN_KEY, token);
    localStorage.setItem(USER_SESSION_KEY, JSON.stringify(nextUser));
    setAuthHeader(token);
    setUser(nextUser);
  };

  const clearSession = () => {
    localStorage.removeItem(AUTH_TOKEN_KEY);
    localStorage.removeItem(USER_SESSION_KEY);
    setAuthHeader();
    setUser(null);
  };

  useEffect(() => {
    const token = getStoredToken();
    const storedUser = parseStoredUser();

    if (!token) {
      setIsLoading(false);
      return;
    }

    // Set initial user from storage immediately on mount (safe for hydration now)
    if (storedUser) {
      setUser(storedUser);
    }

    setAuthHeader(token);

    let isMounted = true;
    api
      .get('/user')
      .then((response) => {
        if (!isMounted) return;
        localStorage.setItem(USER_SESSION_KEY, JSON.stringify(response.data));
        setUser(response.data);
      })
      .catch(() => {
        if (!isMounted) return;
        clearSession();
      })
      .finally(() => {
        if (!isMounted) return;
        setIsLoading(false);
      });

    return () => {
      isMounted = false;
    };
  }, []);

  const login = async (email: string, password: string, portal: AuthPortal = 'public') => {
    const response = await api.post('/login', {
      email,
      password,
      portal,
      ...getDevicePayload(),
    });

    const { user: nextUser, token } = response.data;
    persistSession(nextUser, token);
  };

  const register = async (payload: RegisterPayload) => {
    const response = await api.post('/register', {
      ...payload,
      portal: payload.portal || 'public',
      ...getDevicePayload(),
    });

    const { user: nextUser, token } = response.data;
    persistSession(nextUser, token);
  };

  const loginWithGoogle = async (idToken: string, portal: AuthPortal = 'public') => {
    const response = await api.post('/auth/google', {
      id_token: idToken,
      portal,
      ...getDevicePayload(),
    });

    const { user: nextUser, token } = response.data;
    persistSession(nextUser, token);
  };

  const logout = async () => {
    try {
      await api.post('/logout');
    } catch {
      // Ignore logout errors (token might be invalid already)
    }

    clearSession();
  };

  const authValue = useMemo(
    () => ({ user, login, register, loginWithGoogle, logout, isLoading }),
    [user, isLoading]
  );

  return (
    <AuthContext.Provider value={authValue}>
      {children}

      {/* Forced Password Setup for Google Users */}
      {user?.needs_password && (
        <SetPasswordModal
          isOpen={true}
          onSuccess={() => {
            // Update context to reflect password was set
            setUser(prev => prev ? { ...prev, needs_password: false } : null);
          }}
        />
      )}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

export { api }; // Export axios instance for other components

'use client';

import { FormEvent, useEffect, useRef, useState } from 'react';
import { useAuth, api } from './auth-context';
import { X, Lock, Loader2, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

declare global {
  interface Window {
    google?: {
      accounts: {
        id?: {
          initialize: (config: {
            client_id: string;
            callback: (response: { credential: string }) => void;
          }) => void;
          renderButton: (
            element: HTMLElement,
            options: {
              theme?: 'outline' | 'filled_blue' | 'filled_black';
              size?: 'small' | 'medium' | 'large';
              text?: 'signin_with' | 'signup_with' | 'continue_with' | 'signin';
              shape?: 'rectangular' | 'pill' | 'circle' | 'square';
              width?: string | number;
              logo_alignment?: 'left' | 'center';
            }
          ) => void;
        };
        oauth2?: {
          initTokenClient: (config: {
            client_id: string;
            scope: string;
            callback: (response: {
              access_token?: string;
              error?: string;
              error_description?: string;
            }) => void;
          }) => {
            requestAccessToken: (options?: { prompt?: '' | 'consent' }) => void;
          };
        };
      };
    };
  }
}

interface LoginModalProps {
  isOpen: boolean;
  onClose?: () => void;
  message?: string;
  initialMode?: 'login' | 'signup';
}

const GOOGLE_SCRIPT_ID = 'google-identity-services-script';

const getErrorMessage = (error: unknown, fallback: string) => {
  if (typeof error === 'object' && error !== null) {
    const maybeMessage = (error as { response?: { data?: { message?: string } } }).response?.data?.message;
    if (maybeMessage) return maybeMessage;
  }
  return fallback;
};

export function LoginModal({
  isOpen,
  onClose,
  message = 'Silakan login untuk mengakses konten ini',
  initialMode = 'login',
}: LoginModalProps) {
  const { login, register, loginWithGoogle } = useAuth();
  const GOOGLE_CLIENT_ID = process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID;

  const [mode, setMode] = useState<'login' | 'signup' | 'forgot'>(initialMode as any);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const googleButtonRef = useRef<HTMLDivElement>(null);

  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');

  const [forgotEmail, setForgotEmail] = useState('');

  const [signupName, setSignupName] = useState('');
  const [signupAvatar, setSignupAvatar] = useState('');
  const [signupEmail, setSignupEmail] = useState('');
  const [signupPassword, setSignupPassword] = useState('');

  useEffect(() => {
    if (!isOpen) return;
    setMode(initialMode as any);
    setError('');
    setSuccessMsg('');
  }, [isOpen, initialMode]);

  useEffect(() => {
    if (!isOpen || !googleButtonRef.current) return;

    if (!GOOGLE_CLIENT_ID) {
      console.error('NEXT_PUBLIC_GOOGLE_CLIENT_ID is missing in frontend environment.');
      return;
    }

    let isMounted = true;

    const initGoogleButton = () => {
      if (!isMounted || !googleButtonRef.current) return;
      if (typeof window === 'undefined') return;

      const googleAccounts = window.google?.accounts?.id;
      if (!googleAccounts) {
        // Retry if script loaded but object isn't attached yet
        setTimeout(initGoogleButton, 150);
        return;
      }

      try {
        googleAccounts.initialize({
          client_id: GOOGLE_CLIENT_ID.trim(),
          callback: async (response: { credential: string }) => {
            if (!isMounted) return;
            setIsLoading(true);
            setError('');
            try {
              await loginWithGoogle(response.credential, 'public');
              onClose?.();
            } catch (err) {
              if (isMounted) setError(getErrorMessage(err, 'Login Google gagal.'));
            } finally {
              if (isMounted) setIsLoading(false);
            }
          },
        });

        // Clear before rendering (important for React Strict Mode where it might double call)
        if (googleButtonRef.current) {
          googleButtonRef.current.innerHTML = '';
          googleAccounts.renderButton(googleButtonRef.current, {
            theme: 'outline',
            size: 'large',
            shape: 'pill',
            text: mode === 'signup' ? 'signup_with' : 'signin_with',
            width: 320,
            logo_alignment: 'left',
          });
        }
      } catch (err) {
        console.error('[GoogleAuth] Error rendering button:', err);
      }
    };

    if (window.google?.accounts?.id) {
      initGoogleButton();
    } else {
      let script = document.getElementById(GOOGLE_SCRIPT_ID) as HTMLScriptElement | null;
      if (!script) {
        script = document.createElement('script');
        script.id = GOOGLE_SCRIPT_ID;
        script.src = 'https://accounts.google.com/gsi/client';
        script.async = true;
        script.defer = true;
        document.head.appendChild(script);
      }
      script.addEventListener('load', initGoogleButton);
      return () => {
        isMounted = false;
        script?.removeEventListener('load', initGoogleButton);
      };
    }

    return () => {
      isMounted = false;
    };
  }, [isOpen, mode, loginWithGoogle, onClose, GOOGLE_CLIENT_ID]);

  if (!isOpen) return null;

  const handleEmailLogin = async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      await login(loginEmail, loginPassword, 'public');
      onClose?.();
    } catch (err) {
      setError(getErrorMessage(err, 'Login gagal. Periksa email dan password Anda.'));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSignUp = async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      await register({
        name: signupName,
        email: signupEmail,
        password: signupPassword,
        avatar: signupAvatar || undefined,
        portal: 'public',
      });
      onClose?.();
    } catch (err) {
      setError(getErrorMessage(err, 'Registrasi gagal. Mohon cek data Anda.'));
    } finally {
      setIsLoading(false);
    }
  };

  const handleForgotPassword = async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      const res = await api.post('/auth/forgot-password', { email: forgotEmail });
      setSuccessMsg(res.data.message || 'Tautan reset password telah dikirim ke email Anda.');
    } catch (err) {
      setError(getErrorMessage(err, 'Gagal mengirim permintaan reset password.'));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 pt-20 md:pt-24">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/80 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Modal Content */}
      <div className="relative bg-card w-full max-w-md rounded-2xl shadow-2xl overflow-hidden border border-border animate-in fade-in zoom-in duration-200 max-h-[90vh] overflow-y-auto">

        {/* Header */}
        <div className="p-6 bg-muted/30 text-center relative">
          {onClose && (
            <button
              onClick={onClose}
              className="absolute top-4 right-4 p-2 rounded-full hover:bg-muted transition-colors"
              aria-label="Tutup modal login"
            >
              <X className="w-4 h-4 text-muted-foreground" aria-hidden="true" />
            </button>
          )}

          <div className="w-16 h-16 bg-accent/10 rounded-full flex items-center justify-center mx-auto mb-4">
            <Lock className="w-8 h-8 text-accent" />
          </div>

          <h2 className="text-xl font-bold mb-2">Login Diperlukan</h2>
          <p className="text-sm text-muted-foreground">
            {message}
          </p>
        </div>

        {/* Body */}
        <div className="p-6 space-y-4">

          {mode !== 'forgot' && (
            <div className="flex rounded-xl bg-muted p-1">
              <button
                type="button"
                onClick={() => {
                  setMode('login');
                  setError('');
                }}
                className={`flex-1 rounded-lg px-3 py-2 text-sm font-semibold transition-colors ${mode === 'login' ? 'bg-background text-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
                  }`}
              >
                Masuk
