          {mode !== 'forgot' && GOOGLE_CLIENT_ID ? (
            <div className="flex flex-col items-center gap-2">
              <div ref={googleButtonRef} className="w-full flex justify-center" />
              <p className="text-[11px] text-muted-foreground text-center">
