      description,
      canonical: canonicalUrl,
      ogImage: imageUrl,
      ogType: 'article',
      publishedTime: publishedDate,
      updatedTime: updatedDate,
      authors,
      tags: [...DEFAULT_SEO_KEYWORDS, ...(tags || [])],
    }
  );
};

